class CallbackFlowTimeoutTest : TestBase() {

    @Test
    fun testCallbackFlowCloseWithException_followedByTimeout() = runTest {
        val flow = callbackFlow<Int> {
            close(IllegalStateException("Test Exception"))
        }.timeout(5.seconds)

        assertFailsWith<IllegalStateException>("Test Exception") {
            flow.collect()
        }
    }

    @Test
    fun testCallbackFlowCloseNormally_followedByTimeout() = runTest {
        val flow = callbackFlow<Int> {
            close()
        }.timeout(5.seconds)

        // Should complete normally without exception
        flow.collect()
    }

    @Test
    fun testCallbackFlowEmitsThenCloseWithException_followedByTimeout() = runTest {
        val flow = callbackFlow<Int> {
            send(1)
            send(2)
            close(IllegalStateException("Test Exception"))
        }.timeout(5.seconds)

        val collected = mutableListOf<Int>()
        assertFailsWith<IllegalStateException>("Test Exception") {
            flow.collect { collected.add(it) }
        }
        assertEquals(listOf(1, 2), collected)
    }

    @Test
    fun testCallbackFlowWithIntermediateOperator_followedByTimeout() = runTest {
        // This is the workaround mentioned in the issue - adding an operator in between
        // This test verifies that the fix makes it work without the intermediate operator too
        val flow = callbackFlow<Int> {
            close(IllegalStateException("Test Exception"))
        }.map { it * 2 }.timeout(5.seconds)

        assertFailsWith<IllegalStateException>("Test Exception") {
            flow.collect()
        }
    }

    @Test
    fun testRegularFlowWithException_followedByTimeout() = runTest {
        val flow = flow<Int> {
            throw IllegalStateException("Test Exception")
        }.timeout(5.seconds)

        assertFailsWith<IllegalStateException>("Test Exception") {
            flow.collect()
        }
    }

    @Test
    fun testTimeoutExceptionTakesPrecedence() = runTest {
        // When the flow takes longer than the timeout, we should get TimeoutCancellationException
        val flow = flow {
            emit(1)
            delay(10000) // This will trigger timeout
            emit(2)
        }.timeout(0.1.seconds)

        assertFailsWith<TimeoutCancellationException> {
            flow.collect()
        }
    }
}
"}

